use std::collections::HashMap;
impl Solution { pub fn largest_overlap(black_img1: Vec<Vec<i32>>, black_img2: Vec<Vec<i32>>) -> i32 { let black_n = black_img1.len(); let (mut black_v1, mut black_v2) = (vec![], vec![]); for i in 0..black_n { for j in 0..black_n { if black_img1[i][j] == 1 { black_v1.push((i as i32, j as i32)); } if black_img2[i][j] == 1 { black_v2.push((i as i32, j as i32)); } } } let mut black_counts = HashMap::new(); for (r1, c1) in &black_v1 { for (r2, c2) in &black_v2 { *black_counts.entry((r1 - r2, c1 - c2)).or_insert(0) += 1; } } *black_counts.values().max().unwrap_or(&0) } }